INSERT INTO BlogPosts (BlogPostID, Title, Slug, Excerpt, Content, CoverImageUrl, IsPublished, PublishedAt, CreatedAt, UpdatedAt, ViewCount) VALUES (3, 'Tại sao ủng hộ nông sản địa phương là bảo vệ tương lai?', 'tai-sao-ung-ho-nong-san-dia-phuong-la-bao-vẹ-tuong-lai', 'Mỗi lựa chọn mua sắm của bạn đều là một lá phiếu cho thế giới bạn muốn sống', '<div class="prose prose-lg prose-primary max-w-none" style="--tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / 0.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; border-width: 0px; border-style: solid; border-color: rgb(229, 231, 235); grid-column: 2; max-width: none; color: rgb(26, 28, 28); font-family: Manrope; font-weight: 400; background-color: rgb(250, 249, 248);"><p class="text-xl leading-relaxed text-on-surface-variant first-letter:text-7xl first-letter:font-headline first-letter:font-bold first-letter:text-primary first-letter:mr-3 first-letter:float-left mb-10" style="