INSERT INTO BlogPosts (BlogPostID, Title, Slug, Excerpt, Content, CoverImageUrl, IsPublished, PublishedAt, CreatedAt, UpdatedAt, ViewCount) VALUES (4, 'BÍ QUYẾT BẢO QUẢN RAU XANH TƯƠI ĐẾN 2 TUẦN – ĐƠN GIẢN MÀ HIỆU QUẢ', 'bi-quyet-bao-quan-rau-xanh-tuoi-den-2-tuan-don-gian-ma-hieu-qua', 'Rau xanh là thực phẩm không thể thiếu trong bữa ăn hằng ngày, nhưng lại rất dễ bị héo, úng hoặc hư hỏng nếu không bảo quản đúng cách. Dưới đây là những bí quyết giúp bạn giữ rau tươi lâu đến 2 tuần mà vẫn đảm bảo dinh dưỡng và độ ngon.', 'Rau xanh là thực phẩm không thể thiếu trong bữa ăn hằng ngày, nhưng lại rất dễ bị héo, úng hoặc hư hỏng nếu không bảo quản đúng cách. Dưới đây là những bí quyết giúp bạn giữ rau tươi lâu đến 2 tuần mà vẫn đảm bảo dinh dưỡng và độ ngon.
INSERT INTO BlogPosts (BlogPostID, Title, Slug, Excerpt, Content, CoverImageUrl, IsPublished, PublishedAt, CreatedAt, UpdatedAt, ViewCount) VALUES (5, 'Tại sao nên chọn rau củ hữu cơ cho bữa ăn gia đình?', 'tai-sao-nen-chon-rau-cu-huu-co-cho-bua-an-gia-dinh', 'Khám phá những giá trị thực sự ẩn sau lớp vỏ mộc mạc của rau củ hữu cơ và cách chúng thay đổi sức khỏe của bạn từ bên trong.', '<br><div><div class="prose prose-stone prose-lg max-w-none text-on-surface leading-relaxed font-body" style="--tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / 0.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; border-width: 0px; border-style: solid; border-color: rgb(229, 231, 235); max-width: none; font-family: Manrope; line-height: 1.625; --tw-text-opacity: 1; color: rgb(26, 28, 28); font-weight: 400; background-color: rgb(250, 249, 248); cursor: crosshair !important;"><p class="text-xl text-on-surface-variant mb-10 leading-relaxed font-medium cursor-text" spellcheck="false" data-stitch-editable-idx="16" data-stitch-added-classes="cursor-text" style="--tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / 0.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; border-width: 0px; border-style: solid; border-color: rgb(229, 231, 235); cursor: text; margin-top: 0px; margin-bottom: 2.5rem; font-size: 1.25rem; line-height: 1.625; --tw-text-opacity: 1; color: rgb(62, 74, 62);">Trong những năm gần đây, xu hướng sử dụng thực phẩm hữu cơ (organic) không chỉ là một trào lưu nhất thời mà đã trở thành một lựa chọn sống lành mạnh được nhiều gia đình Việt tin dùng. Nhưng điều gì thực sự khiến rau củ hữu cơ trở nên khác biệt?</p><h2 class="text-3xl font-bold text-primary mt-12 mb-6 cursor-text" spellcheck="false" data-stitch-editable-idx="17" data-stitch-added-classes="cursor-text" style="--tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-transla