INSERT INTO HomePageSettings (Id, SettingsJson, UpdatedAt) VALUES (1, '{"hero":{"eyebrow":"FRESH FROM THE FARM","title":"Th\u1EF1c ph\u1EA9m s\u1EA1ch cho","highlight":"cu\u1ED9c s\u1ED1ng xanh","subtitle":"Mang tinh hoa c\u1EE7a \u0111\u1EA5t m\u1EB9 \u0111\u1EBFn b\u00E0n \u0103n gia \u0111\u00ECnh b\u1EA1n. Ch\u00FAng t\u00F4i cam k\u1EBFt 100% h\u1EEFu c\u01A1, t\u01B0\u01A1i m\u1EDBi v\u00E0 canh t\u00E1c b\u1EC1n v\u1EEFng.","imageUrl":"/home-assets/f9be5c7895e7407ba9224ba124e4bef7.png","primaryCtaText":"Kh\u00E1m ph\u00E1","primaryCtaHref":"/products","secondaryCtaText":"View Story","secondaryCtaHref":null,"feature1Title":"Giao h\u00E0ng trong 2h","feature1Sub":"Nhanh ch\u00F3ng \u0026 ti\u1EC7n l\u1EE3i","feature2Title":"\u0110\u1EA3m b\u1EA3o ATVSTP","feature2Sub":"Ki\u1EC3m duy\u1EC7t nghi\u00EAm ng\u1EB7t"},"roots":{"subheading":"OUR ROOTS","title":"L\u1EDBn l\u00EAn v\u1EDBi ni\u1EC1m \u0111am m\u00EA,\u0111\u01B0\u1EE3c truy\u1EC1n t\u1EA3i b\u1EB1ng tr\u00E1i tim.","paragraph1":"T\u1EEB nh\u1EEFng ng\u00E0y \u0111\u1EA7u ti\u00EAn t\u1EA1i n\u00F4ng tr\u1EA1i h\u1EEFu c\u01A1 nh\u1ECF, ch\u00FAng t\u00F4i lu\u00F4n tin r\u1EB1ng th\u1EF1c ph\u1EA9m t\u1ED1t nh\u1EA5t l\u00E0 th\u1EF1c ph\u1EA9m \u0111\u01B0\u1EE3c nu\u00F4i d\u01B0\u1EE1ng b\u1EDFi t\u1EF1 nhi\u00EAn v\u00E0 s\u1EF1 ch\u0103m s\u00F3c t\u1EEB t\u00E2m.","paragraph2":"M\u1ED7i s\u1EA3n ph\u1EA9m t\u1EA1i FreshFood \u0111\u1EC1u tr\u1EA3i qua quy tr\u00ECnh ki\u1EC3m so\u00E1t nghi\u00EAm ng\u1EB7t t\u1EEB h\u1EA1t gi\u1ED1ng \u0111\u1EBFn khi trao t\u1EADn tay kh\u00E1ch h\u00E0ng. Kh\u00F4ng h\u00F3a ch\u1EA5t, kh\u00F4ng thu\u1ED1c tr\u1EEB s\u00E2u - ch\u1EC9 c\u00F3 s\u1EF1 tinh khi\u1EBFt tuy\u1EC7t \u0111\u1ED1i cho s\u1EE9c kh\u1ECFe gia \u0111\u00ECnh b\u1EA1n.","imageUrl":"https://lh3.googleusercontent.com/aida-public/AB6AXuDsj_dBOI4I0rXNR9uejFIaPEYVYQLiGunw26FXWSFWv8bh-uXHvGgsQsg_XTphaN30FjcrZ-zZvN1zLeAy9-L0P21Vb5NEEbJZ-udrnGjuUD8oXHa4P3CgVcJ44tFQXwszRhO4rqxV3sGWuBfqtJ7aAcKYwZpFTiIEiEn6Q0bK0gDvCvPdtucaAkTpSSL_YANkAVAhLYv5EFW-rtmR0wFVAIEamv0iDUPhzmDHsk6HgLEDPQgOGkgMEv47w-wVzGBjlAicFc822N8","stat1Value":"100%","stat1Label":"Organic Certified","stat2Value":"24h","stat2Label":"Farm to Door"},"seasonal":{"heading":"B\u1ED9 s\u01B0u t\u1EADp theo m\u00F9a","subheading":"\u0110\u00F3n m\u00F9a v\u1EE5 t\u01B0\u01A1i ngon nh\u1EA5t trong n\u0103m. Kh\u00E1m ph\u00E1 nh\u1EEFng b\u1ED9 s\u01B0u t\u1EADp \u0111\u01B0\u1EE3c tuy\u1EC3n ch\u1ECDn theo m\u00F9a v\u1EE5 hi\u1EC7n t\u1EA1i.","cards":{"title":"The Spring Greens","imageUrl":"https://images.pexels.com/photos/60597/dahlia-red-blossom-bloom-60597.jpeg"},{"title":"Earthy Roots","imageUrl":"https://images.pexels.com/photos/1301856/pexels-photo-1301856.jpeg"},{"title":"Sun-Kissed Fruits","imageUrl":"https://images.pexels.com/photos/1132047/pexels-photo-1132047.jpeg"}}}', '2026-04-23T07:14:13.0565657')
