INSERT INTO Products (ProductID, ProductName, CategoryID, SupplierID, Price, StockQuantity, Unit, Description, CreatedAt, DiscountPrice, Sku, ManufacturedDate, ExpiryDate, Origin, StorageInstructions, Certifications, Status) VALUES (40, 'Trà Xanh Thái Nguyên', 7, 1, CAST(150000.00 AS Decimal(18, 2)), 13, 'Gói 200g', 'Trà xanh tân cương, thơm hương cốm', '2026-04-07T10:38:11.640', NULL, 'FF-PRD-040', '2026-03-13T09:28:42.8300000', '2026-10-13T09:28:42.8300000', 'Thái Nguyên', 'Nơi khô ráo', 'OCOP', 'Active')
INSERT INTO Products (ProductID, ProductName, CategoryID, SupplierID, Price, StockQuantity, Unit, Description, CreatedAt, DiscountPrice, Sku, ManufacturedDate, ExpiryDate, Origin, StorageInstructions, Certifications, Status) VALUES (41, 'Combo Nấu Canh Gia Đình', 9, 2, CAST(70000.00 AS Decimal(18, 2)), 7, 'Combo (2kg)', 'Combo rau củ tươi sạch gồm cà rốt, khoai tây, củ cải trắng, hành tây, cà chua và hành lá, rau mùi – tất cả được chọn lọc kỹ lưỡng để đảm bảo độ tươi ngon và dinh dưỡng. Sản phẩm phù hợp để chế biến các món canh, hầm xương hoặc nấu súp cho gia đình từ 3–5 người. Rau củ có vị ngọt tự nhiên, giúp món ăn đậm đà hơn mà không cần nhiều gia vị.', '2026-04-08T06:59:55.353', CAST(60000.00 AS Decimal(18, 2)), 'FF-COMBONAU-041', '2026-04-13T09:28:42.8333333', '2026-04-16T09:28:42.8333333', 'FreshFood Việt Nam', 'Bảo quản lạnh, dùng sớm', 'Đảm bảo VSATTP', 'Active')
INSERT INTO Products (ProductID, ProductName, CategoryID, SupplierID, Price, StockQuantity, Unit, Description, CreatedAt, DiscountPrice, Sku, ManufacturedDate, ExpiryDate, Origin, StorageInstructions, Certifications, Status) VALUES (42, 'Combo Salad Eat Clean', 9, 2, CAST(66000.00 AS Decimal(18, 2)), 33, 'combo (1.2kg)', 'Combo bao gồm xà lách tươi, cà chua bi, dưa leo, ớt chuông, bắp ngọt và cà rốt – đều là những nguyên liệu giàu vitamin, chất xơ và ít calo. Rau được chọn loại tươi, sạch, phù hợp ăn sống hoặc làm salad. Đây là lựa chọn lý tưởng cho người ăn kiêng, tập gym hoặc theo chế độ eat clean, giúp hỗ trợ giảm cân và làm đẹp da.', '2026-04-08T07:48:10.940', CAST(55000.00 AS Decimal(18, 2)), 'FF-COMBOSAL-042', '2026-04-13T09:28:42.8333333', '2026-04-16T09:28:42.8333333', 'FreshFood Việt Nam', 'Bảo quản lạnh, dùng sớm', 'Đảm bảo VSATTP', 'Active')
INSERT INTO Products (ProductID, ProductName, CategoryID, SupplierID, Price, StockQuantity, Unit, Description, CreatedAt, DiscountPrice, Sku, ManufacturedDate, ExpiryDate, Origin, StorageInstructions, Certifications, Status) VALUES (43, 'Combo Nước Ép Detox', 9, 2, CAST(120000.00 AS Decimal(18, 2)), 95, 'combo (2.5kg)', 'Combo trái cây và rau củ gồm táo, cam, cà rốt, dưa leo, cần tây và gừng – kết hợp hoàn hảo để ép nước hoặc làm sinh tố detox. Các nguyên liệu giàu vitamin C, chất chống oxy hóa và khoáng chất giúp thanh lọc cơ thể, tăng cường sức đề kháng và hỗ trợ tiêu hóa. Phù hợp sử dụng hằng ngày để duy trì lối sống lành mạnh.', '2026-04-08T07:50:33.107', CAST(100000.00 AS Decimal(18, 2)), 'FF-COMBONUO-043', '2026-04-13T09:28:42.8333333', '2026-04-16T09:28:42.8333333', 'FreshFood Việt Nam', 'Bảo quản lạnh, dùng sớm', 'Đảm bảo VSATTP', 'Active')
INSERT INTO Products (ProductID, ProductName, CategoryID, SupplierID, Price, StockQuantity, Unit, Description, CreatedAt, DiscountPrice, Sku, ManufacturedDate, ExpiryDate, Origin, StorageInstructions, Certifications, Status) VALUES (44, 'Combo "Đại Dương Thịnh Vượng"', 10, 3, CAST(3000000.00 AS Decimal(18, 2)), 22, 'combo (2.5kg - 3.0kg)', 'Sự kết hợp đẳng cấp giữa các loại hải sản nhập khẩu và đặc sản cao cấp, phù hợp cho các buổi tiệc gia đình quan trọng hoặc tiếp đãi đối tác. Hải sản được chế biến sốt bơ tỏi hoặc hấp rượu vang trắng. Thành phần: * 1 con Tôm hùm Alaska.
INSERT INTO Products (ProductID, ProductName, CategoryID, SupplierID, Price, StockQuantity, Unit, Description, CreatedAt, DiscountPrice, Sku, ManufacturedDate, ExpiryDate, Origin, StorageInstructions, Certifications, Status) VALUES (45, 'Combo "Gió Biển Miền Trung"', 10, 3, CAST(1400000.00 AS Decimal(18, 2)), 26, 'combo 2.2kg', 'Tập trung vào các loại hải sản đặc trưng của vùng biển Việt Nam với hương vị đậm đà. Phù hợp cho nhóm bạn nhậu hoặc họp mặt cuối tuần. Đi kèm là các loại nước chấm muối ớt xanh đặc sản.
