INSERT INTO Reviews (ReviewID, ProductID, UserID, Rating, Comment, ReviewDate, ModerationStatus, ModeratedAt, ModerationNote, AdminReply, RepliedAt, IsDeleted, DeletedAt) VALUES (9, 35, 6, 5, 'Hạt nêm Knorr này thì quá quen thuộc rồi, nêm canh hay ướp thịt đều đậm đà, dậy mùi xương ống rất tự nhiên. Gói 400g giá 55k dùng được khá lâu, hạt tơi không bị vón cục. Nội trợ mà thiếu em này là thiếu đi "linh hồn" món ăn!', '2026-04-13T14:02:54.840', 'Approved', '2026-04-13T07:03:55.5622254', NULL, 'Dạ chào bạn, cảm ơn bạn đã tin tưởng lựa chọn hạt nêm Knorr tại shop! Những lời khen của bạn là động lực rất lớn để shop tiếp tục mang đến sản phẩm chất lượng và dịch vụ tốt nhất. Chúc bạn có thêm nhiều bữa ăn ngon miệng cùng gia đình nhé!', '2026-04-13T07:03:46.5395449', 0, NULL)
INSERT INTO Reviews (ReviewID, ProductID, UserID, Rating, Comment, ReviewDate, ModerationStatus, ModeratedAt, ModerationNote, AdminReply, RepliedAt, IsDeleted, DeletedAt) VALUES (10, 35, 7, 5, 'Cảm giác hạt nêm dạo này hơi mặn hơn trước, nêm quá tay một chút là lấn át hết vị ngọt của rau củ. Thành phần vẫn còn nhiều bột ngọt nên ai nhạy cảm sẽ thấy hơi khô cổ sau khi ăn. Giá 55k cho gói 400g cũng không rẻ so với các dòng hạt nêm khác.', '2026-04-13T14:31:42.557', 'Hidden', '2026-04-13T08:04:37.3047047', 'Chào bạn, shop rất tiếc vì trải nghiệm của bạn chưa được trọn vẹn. Shop xin ghi nhận góp ý về hương vị và giá thành để phản hồi lại với nhà cung cấp nhằm cải thiện sản phẩm tốt hơn. Hy vọng bạn vẫn sẽ cho shop cơ hội được phục vụ bạn tốt hơn trong những lần tới ạ!', NULL, NULL, 0, NULL)
